('spanish:7-2-my-region-and-places-of-interest:mcq:d7beb85b', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"En mi ciudad hay un castillo histórico.\" data-listen></span><br>Listen. What is in the city?", "options": ["A modern art museum", "A historic castle", "An old stone church", "A small local market"]}'::jsonb, '{"answer": 1, "explain": "‘hay un castillo histórico’ = there is a historic castle. The other buildings are all plausible but not what was said."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:666ae372', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"El museo está a la derecha de la plaza.\" data-listen></span><br>Listen. Where is the museum?", "options": ["To the left of the square", "Straight ahead of the market", "Next to the cathedral entrance", "To the right of the square"]}'::jsonb, '{"answer": 3, "explain": "‘a la derecha de’ = to the right of. Distractors swap the direction word or the landmark named."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:c7096013', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Hace mucho frío en invierno.\" data-listen></span><br>Listen. What is the weather like?", "options": ["It’s very cold in winter", "It’s very hot in summer", "It’s quite windy on the coast", "It rains a lot in the spring"]}'::jsonb, '{"answer": 0, "explain": "‘hace frío’ = it’s cold; ‘invierno’ = winter. Distractors swap the season or the weather word."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:d8a6a692', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "Which word means ‘the countryside’?", "options": ["el pueblo", "la costa", "el campo", "el mercado"]}'::jsonb, '{"answer": 2, "explain": "el campo = the countryside. pueblo = town/village, costa = coast, mercado = market — all real vocab, easy to muddle."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:707fd180', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "Complete: ‘En mi región ___ un castillo y una catedral.’", "options": ["es", "hay", "está", "son"]}'::jsonb, '{"answer": 1, "explain": "‘hay’ (there is/are) introduces something and never changes form. es/está/son all need a specific, already-known subject."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:cf9bd193', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "Which sentence correctly uses ‘estar’ for location?", "options": ["Mi pueblo es en el sur de España", "Mi pueblo hay en el sur de España", "Mi pueblo tiene en el sur de España", "Mi pueblo está en el sur de España"]}'::jsonb, '{"answer": 3, "explain": "Location takes estar: está en el sur. ser/hay/tener cannot be used to say where something is."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:18aebc74', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "Which sentence correctly uses ‘ser’ for a permanent description?", "options": ["Mi ciudad es histórica y turística", "Mi ciudad está histórica y turística", "Mi ciudad hay histórica y turística", "Mi ciudad tiene histórica y turística"]}'::jsonb, '{"answer": 0, "explain": "A lasting characteristic uses ser: es histórica. The other verbs cannot combine with an adjective this way."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:58dc07fb', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "What does ‘lejos de’ mean?", "options": ["close to, nearby", "right next to", "far from", "straight on ahead"]}'::jsonb, '{"answer": 2, "explain": "lejos de = far from, the opposite of cerca de (close to)."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:5fb929a2', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "Higher: which sentence uses the relative pronoun correctly?", "options": ["Es una ciudad quien tiene mucha historia", "Es una ciudad cual tiene mucha historia", "Es una ciudad donde tiene mucha historia", "Es una ciudad que tiene mucha historia"]}'::jsonb, '{"answer": 3, "explain": "‘que’ links the noun to extra information here; quien/cual/donde are the wrong relative words for this structure."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:mcq:116ebdec', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'mcq', 'mcq', 1, '{"question": "Complete: ‘Se puede ___ el castillo los fines de semana.’", "options": ["visita", "visitar", "visitando", "visitado"]}'::jsonb, '{"answer": 1, "explain": "‘se puede’ + infinitive → visitar. visita/visitando/visitado are conjugated or non-finite forms that don’t follow se puede."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tf:a894f5fe', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tf', 'tf', 1, '{"question": "‘hay’ means ‘there is / there are’ and never changes form."}'::jsonb, '{"answer": true, "explain": "hay un castillo, hay dos castillos — hay is always invariable."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tf:e3373e3b', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tf', 'tf', 1, '{"question": "You use ‘ser’ to say exactly where a place is located."}'::jsonb, '{"answer": false, "explain": "Location uses estar (está en el norte); ser is for permanent characteristics."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tf:31533d7f', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tf', 'tf', 1, '{"question": "‘todo recto’ means ‘straight on’."}'::jsonb, '{"answer": true, "explain": "todo recto = straight on/ahead when giving directions."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tf:000c7948', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tf', 'tf', 1, '{"question": "‘lejos de’ means ‘close to’."}'::jsonb, '{"answer": false, "explain": "lejos de = far from; cerca de = close to."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tf:a4a9cd90', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tf', 'tf', 1, '{"question": "‘llueve’ means ‘it rains’."}'::jsonb, '{"answer": true, "explain": "llueve comes from llover, to rain."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tf:5d5e4809', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tf', 'tf', 1, '{"question": "‘se puede’ + infinitive means ‘you can…’."}'::jsonb, '{"answer": true, "explain": "se puede visitar = you can visit."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tf:ae908785', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tf', 'tf', 1, '{"question": "‘antiguo’ means ‘modern’."}'::jsonb, '{"answer": false, "explain": "antiguo means old/ancient; moderno means modern."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tf:2e1801ac', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tf', 'tf', 1, '{"question": "‘que’ can introduce a relative clause, e.g. ‘una ciudad que tiene mucha historia’."}'::jsonb, '{"answer": true, "explain": "que links a noun to extra information — a Higher-tier structure."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:learn:cad90076', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe my area or region?", "reading": "<p>Use these nouns to say what kind of place you live in, and the compass points to say where it is. Tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mi región\">mi región</span></td><td>my region</td><td><span data-say=\"mi ciudad\">mi ciudad</span></td><td>my city</td></tr>\n              <tr><td><span data-say=\"el pueblo\">el pueblo</span></td><td>the town / village</td><td><span data-say=\"la costa\">la costa</span></td><td>the coast</td></tr>\n              <tr><td><span data-say=\"el campo\">el campo</span></td><td>the countryside</td><td><span data-say=\"el norte\">el norte</span></td><td>the north</td></tr>\n              <tr><td><span data-say=\"el sur\">el sur</span></td><td>the south</td><td><span data-say=\"el este\">el este</span></td><td>the east</td></tr>\n              <tr><td><span data-say=\"el oeste\">el oeste</span></td><td>the west</td><td><span data-say=\"vivo en\">vivo en…</span></td><td>I live in…</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Vivo en un pueblo pequeño en el norte de España, cerca de la costa.\">Vivo en un pueblo pequeño en el norte de España, cerca de la costa.</span> — <em>I live in a small town in the north of Spain, near the coast.</em></p>", "question": "What does ‘el campo’ mean?", "options": ["the north coastline", "the town centre square", "the countryside", "the eastern border area"]}'::jsonb, '{"answer": 2, "explain": "el campo = the countryside. The distractors invent locations that aren’t what campo means."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:learn:ed1a564b', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'learn', 'mcq', 1, '{"readingTitle": "What places of interest are there? (hay + noun)", "reading": "<p>To say something exists somewhere, use <strong>hay</strong> (there is / there are) — it never changes form, whether the noun is singular or plural.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el museo\">el museo</span></td><td>the museum</td><td><span data-say=\"el castillo\">el castillo</span></td><td>the castle</td></tr>\n              <tr><td><span data-say=\"la catedral\">la catedral</span></td><td>the cathedral</td><td><span data-say=\"la iglesia\">la iglesia</span></td><td>the church</td></tr>\n              <tr><td><span data-say=\"la plaza\">la plaza</span></td><td>the square</td><td><span data-say=\"el monumento\">el monumento</span></td><td>the monument</td></tr>\n              <tr><td><span data-say=\"el parque\">el parque</span></td><td>the park</td><td><span data-say=\"el mercado\">el mercado</span></td><td>the market</td></tr>\n              <tr><td><span data-say=\"el teatro\">el teatro</span></td><td>the theatre</td><td><span data-say=\"hay\">hay</span></td><td>there is / are</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En mi ciudad hay un castillo histórico, una catedral bonita y muchos museos.\">En mi ciudad hay un castillo histórico, una catedral bonita y muchos museos.</span> — <em>In my city there is a historic castle, a pretty cathedral and lots of museums.</em></p>", "question": "Which word means ‘there is / there are’ and never changes form?", "options": ["está", "hay", "son", "tiene"]}'::jsonb, '{"answer": 1, "explain": "hay is invariable — un castillo hay, dos castillos hay. está/son/tiene all change and need a different structure."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:learn:6027a592', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe places? (ser vs estar)", "reading": "<p>Use <strong>ser</strong> for a permanent characteristic (what a place is like), and <strong>estar</strong> for where it is located — never mix them up.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"histórico\">histórico / histórica</span></td><td>historic</td><td><span data-say=\"turístico\">turístico / turística</span></td><td>touristy</td></tr>\n              <tr><td><span data-say=\"tranquilo\">tranquilo / tranquila</span></td><td>quiet, peaceful</td><td><span data-say=\"animado\">animado / animada</span></td><td>lively</td></tr>\n              <tr><td><span data-say=\"bonito\">bonito / bonita</span></td><td>pretty</td><td><span data-say=\"industrial\">industrial</span></td><td>industrial</td></tr>\n              <tr><td><span data-say=\"moderno\">moderno / moderna</span></td><td>modern</td><td><span data-say=\"antiguo\">antiguo / antigua</span></td><td>old, ancient</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Mi ciudad es muy turística y animada, pero está lejos de la costa.\">Mi ciudad es muy turística y animada, pero está lejos de la costa.</span> — <em>My city is very touristy and lively, but it is far from the coast.</em></p>", "question": "Which verb do you use for ‘my town IS historic’ — a permanent characteristic?", "options": ["estar → mi pueblo está histórico", "hay → mi pueblo hay histórico", "tener → mi pueblo tiene histórico", "ser → mi pueblo es histórico"]}'::jsonb, '{"answer": 3, "explain": "A lasting characteristic uses ser: es histórico. estar/hay/tener cannot combine with an adjective this way."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:learn:58dc07fb', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'learn', 'mcq', 1, '{"readingTitle": "How do I ask for and give directions?", "reading": "<p>Use <strong>estar</strong> to say exactly where something is once it has already been introduced with hay.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"¿dónde está?\">¿Dónde está…?</span></td><td>Where is…?</td><td><span data-say=\"a la derecha\">a la derecha</span></td><td>to the right</td></tr>\n              <tr><td><span data-say=\"a la izquierda\">a la izquierda</span></td><td>to the left</td><td><span data-say=\"todo recto\">todo recto</span></td><td>straight on</td></tr>\n              <tr><td><span data-say=\"cerca de\">cerca de</span></td><td>close to, near</td><td><span data-say=\"lejos de\">lejos de</span></td><td>far from</td></tr>\n              <tr><td><span data-say=\"al lado de\">al lado de</span></td><td>next to</td><td><span data-say=\"en el centro\">en el centro</span></td><td>in the centre</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El museo está al lado de la catedral: todo recto y luego a la derecha.\">El museo está al lado de la catedral: todo recto y luego a la derecha.</span> — <em>The museum is next to the cathedral: straight on and then to the right.</em></p>", "question": "What does ‘lejos de’ mean?", "options": ["far from", "close to, near", "next to, beside", "straight on ahead"]}'::jsonb, '{"answer": 0, "explain": "lejos de = far from — the opposite of cerca de (close to)."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:learn:239b8c62', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about the weather and climate?", "reading": "<p>Weather is usually described with <strong>hacer</strong> or an impersonal verb like <strong>llover</strong> (to rain).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hace sol\">hace sol</span></td><td>it’s sunny</td><td><span data-say=\"hace calor\">hace calor</span></td><td>it’s hot</td></tr>\n              <tr><td><span data-say=\"hace frío\">hace frío</span></td><td>it’s cold</td><td><span data-say=\"hace viento\">hace viento</span></td><td>it’s windy</td></tr>\n              <tr><td><span data-say=\"llueve\">llueve</span></td><td>it rains</td><td><span data-say=\"el clima\">el clima</span></td><td>the climate</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En mi región el clima es agradable: hace sol en verano, pero llueve mucho en invierno.\">En mi región el clima es agradable: hace sol en verano, pero llueve mucho en invierno.</span> — <em>In my region the climate is pleasant: it’s sunny in summer, but it rains a lot in winter.</em></p>", "question": "What does ‘llueve’ mean?", "options": ["it is windy today", "it is very sunny", "it rains", "it is freezing cold"]}'::jsonb, '{"answer": 2, "explain": "llueve = it rains, from llover. The distractors describe other weather words entirely."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:learn:72f8ddcd', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'learn', 'mcq', 1, '{"readingTitle": "Higher: relative clauses, superlatives and se puede", "reading": "<p><span class=\"tier-h\">H</span> Use <strong>que</strong> to join two ideas about the same noun, a superlative for ‘the most…’, and <strong>se puede</strong> + infinitive for ‘you can…’.</p>\n            <ul>\n              <li><span data-say=\"una ciudad que tiene mucha historia\">una ciudad que tiene mucha historia</span> — a city that has a lot of history</li>\n              <li><span data-say=\"lo más interesante es el castillo\">lo más interesante es el castillo</span> — the most interesting thing is the castle</li>\n              <li><span data-say=\"se puede visitar el museo\">se puede visitar el museo</span> — you can visit the museum</li>\n            </ul>\n            <p>Combine for the top band: <span data-say=\"Lo más interesante de mi región es el castillo, que tiene más de quinientos años; se puede visitar todos los días.\">Lo más interesante de mi región es el castillo, que tiene más de quinientos años; se puede visitar todos los días.</span> <span class=\"tier-h\">H</span></p>", "question": "Which sentence correctly uses the relative pronoun ‘que’?", "options": ["Es una ciudad quien tiene mucha historia", "Es una ciudad que tiene mucha historia", "Es una ciudad cual tiene mucha historia", "Es una ciudad donde tiene mucha historia"]}'::jsonb, '{"answer": 1, "explain": "‘que’ is the standard relative pronoun linking a noun to extra information here; quien/cual/donde don’t fit this structure."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:misc:4d74f552', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mi ciudad está histórica y turística.</p><p><strong>✅ The correct idea:</strong> Mi ciudad es histórica y turística.</p>", "question": "Why is ‘es’ correct here, not ‘está’?", "options": ["you should always use estar before any kind of descriptive adjective", "histórica actually describes a location, not a characteristic", "histórica is a lasting characteristic, so it needs ser", "es is only ever used for jobs and nationalities"]}'::jsonb, '{"answer": 2, "explain": "Lasting characteristics take ser: es histórica. estar would only be right for a temporary state or a location."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:misc:4edb16fb', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> El castillo hay en el centro de la ciudad.</p><p><strong>✅ The correct idea:</strong> El castillo está en el centro de la ciudad.</p>", "question": "Why is ‘está’ correct, not ‘hay’, once the castle is a specific known place?", "options": ["hay only introduces something new; a specific thing’s location uses estar", "hay and estar always mean exactly the same thing in absolutely every context", "hay can only ever be used inside a question, never inside a statement", "está cannot ever be used to talk about buildings or historic monuments"]}'::jsonb, '{"answer": 0, "explain": "hay introduces (there is a castle); estar then says where that specific castle is."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:misc:6305ce2b', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ‘antiguo’ significa ‘moderno’.</p><p><strong>✅ The correct idea:</strong> ‘antiguo’ significa ‘viejo, de hace mucho tiempo’.</p>", "question": "What does ‘antiguo’ actually mean?", "options": ["modern and brand new", "industrial and busy", "touristy and crowded", "old, ancient"]}'::jsonb, '{"answer": 3, "explain": "antiguo = old/ancient — almost the opposite of moderno."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:misc:58dc07fb', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ‘lejos de’ significa ‘cerca de’.</p><p><strong>✅ The correct idea:</strong> ‘lejos de’ significa ‘far from’, lo opuesto de ‘cerca de’.</p>", "question": "What does ‘lejos de’ mean?", "options": ["close to, nearby", "far from", "right next to", "straight on ahead"]}'::jsonb, '{"answer": 1, "explain": "lejos de = far from; cerca de (close to) is the opposite, a common mix-up."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:misc:df44d99d', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> En mi ciudad hay dos museo y un iglesia.</p><p><strong>✅ The correct idea:</strong> En mi ciudad hay dos museos y una iglesia.</p>", "question": "What are the two mistakes in ‘dos museo y un iglesia’?", "options": ["both of these two separate words simply need to start with a capital letter", "‘dos’ should really be replaced with the whole phrase ‘dos veces’ instead of here", "‘museo’ needs the plural -s and ‘iglesia’ needs ‘una’, not ‘un’ (it’s feminine)", "nothing at all is actually wrong with this particular Spanish sentence at all"]}'::jsonb, '{"answer": 2, "explain": "‘dos museo’ should agree in number (museos); ‘iglesia’ is feminine, so it needs ‘una’, not ‘un’."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tips:7f06c2ad', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Listening for places and directions", "reading": "Listen for ‘hay’ (something exists) versus ‘está’ (where a specific thing is), and for direction words like ‘a la derecha’ / ‘a la izquierda’ / ‘todo recto’ — they sound similar but point opposite ways, so don’t guess from the first syllable.", "question": "You hear ‘a la izquierda’. Which way is that?", "options": ["to the right", "to the left", "straight ahead", "next to the market"]}'::jsonb, '{"answer": 1, "explain": "a la izquierda = to the left; a la derecha = to the right — easy to confuse under exam pressure."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tips:f56b2257', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 3 — Reading & translation into English", "reading": "Watch ser vs estar carefully when translating: ‘es histórica’ (it is historic) is a description, ‘está en el norte’ (it is in the north) is a location — English uses ‘is’ for both, so don’t lose the distinction when you translate the other way.", "question": "‘Mi pueblo es tranquilo pero está lejos de la costa’ =", "options": ["My town is busy and it is close to the coast", "My town is modern but it is near the mountains", "My town is historic and it is next to the market", "My town is quiet but it is far from the coast"]}'::jsonb, '{"answer": 3, "explain": "es tranquilo = is quiet (description); está lejos de la costa = is far from the coast (location)."}'::jsonb),
('spanish:7-2-my-region-and-places-of-interest:tips:2f1a4fab', 'spanish', 'spanish:7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Paper 4 — Writing about my region", "reading": "Build a strong paragraph: introduce with hay, describe with ser, locate with estar, add an opinion, and finish with a Higher-tier relative clause or se puede. Example: ‘En mi región hay un castillo que es muy antiguo; se puede visitar los fines de semana.’", "question": "Which answer reaches the top band?", "options": ["Hay un castillo. Es antiguo. Está en mi región. Es bonito. Es viejo", "Mi región tiene cosas", "En mi región hay un castillo que es muy antiguo y se puede visitar los fines de semana", "Hay un castillo, hay una catedral, hay un museo y también hay un parque muy grande y bonito"]}'::jsonb, '{"answer": 2, "explain": "It links hay, ser, a relative clause and se puede into one fluent sentence — range and accuracy, not just length or a repetitive list of ‘hay’."}'::jsonb),
